  font-size: ${theme.typography.fontSize['2xl']};
  color: ${theme.colors.gray[700]};
  margin-bottom: ${theme.spacing.md};
`;

const EmptyCartMessage = styled.p`
  color: ${theme.colors.gray[600]};
  margin-bottom: ${theme.spacing.xl};
`;

const CartPage = () => {
  const { items, updateItemQuantity, removeItem, getTotalPrice, getTotalItems } = useCart();

  const handleUpdateQuantity = (itemId, change) => {
    const item = items.find(item => item.food_id === itemId);
    if (item) {
      const newQuantity = Math.max(0, item.quantity + change);
      if (newQuantity === 0) {
        removeItem(itemId);
      } else {
        updateItemQuantity(itemId, newQuantity);
      }
    }
  };

  const handleRemoveItem = (itemId) => {
    removeItem(itemId);
  };

  const subtotal = getTotalPrice();
  const tax = subtotal * 0.08; // 8% tax
  const deliveryFee = subtotal > 50 ? 0 : 4.99; // Free delivery over $50
  const total = subtotal + tax + deliveryFee;

  if (items.length === 0) {
    return (
      <CartContainer>
        <CartHeader>
          <BackButton to="/menu">
            <ArrowLeft size={20} />
            Back to Menu
          </BackButton>
          <CartTitle>
            <ShoppingCart size={32} />
            Your Cart
          </CartTitle>
        </CartHeader>

        <EmptyCart>
          <EmptyCartIcon>
            <ShoppingCart size={64} />
          </EmptyCartIcon>
          <EmptyCartTitle>Your cart is empty</EmptyCartTitle>
          <EmptyCartMessage>
            Looks like you haven't added anything to your cart yet. 
            Start browsing our delicious menu!
          </EmptyCartMessage>
          <Button as={Link} to="/menu" size="lg">
            Browse Menu
          </Button>
        </EmptyCart>
      </CartContainer>
    );
  }

  return (
    <CartContainer>
      <CartHeader>
        <BackButton to="/menu">
          <ArrowLeft size={20} />
          Back to Menu
        </BackButton>
        <CartTitle>
          <ShoppingCart size={32} />
          Your Cart ({getTotalItems()} items)
        </CartTitle>
      </CartHeader>

      <CartContent>
        <CartItems>
          {items.map(item => (
            <CartItem key={item.food_id}>
              <ItemImage>
                🍽️
              </ItemImage>

              <ItemDetails>
                <ItemName>{item.name}</ItemName>
                <ItemDescription>{item.description}</ItemDescription>
                <ItemPrice>${(item.price * item.quantity).toFixed(2)}</ItemPrice>
              </ItemDetails>

              <ItemControls>
                <QuantityControl>
                  <QuantityButton
                    onClick={() => handleUpdateQuantity(item.id, -1)}
                    disabled={item.quantity === 1}
                  >
                    <Minus size={16} />
                  </QuantityButton>
                  <QuantityDisplay>{item.quantity}</QuantityDisplay>
                  <QuantityButton
                    onClick={() => handleUpdateQuantity(item.id, 1)}
                  >
                    <Plus size={16} />
                  </QuantityButton>
                </QuantityControl>

                <RemoveButton onClick={() => handleRemoveItem(item.id)}>
                  <Trash2 size={16} />
                  Remove
                </RemoveButton>
              </ItemControls>
            </CartItem>
          ))}
        </CartItems>

        <CartSummary>
          <CardBody>
            <SummaryTitle>Order Summary</SummaryTitle>

            <SummaryItem>
              <span>Subtotal</span>
              <span>${subtotal.toFixed(2)}</span>
            </SummaryItem>

            <SummaryItem>
              <span>Tax (8%)</span>
              <span>${tax.toFixed(2)}</span>
            </SummaryItem>

            <SummaryItem>
              <span>Delivery Fee</span>
              <span>
                {deliveryFee === 0 ? 'FREE' : `$${deliveryFee.toFixed(2)}`}
              </span>
            </SummaryItem>

            <SummaryTotal>
              <span>Total</span>
              <span>${total.toFixed(2)}</span>
            </SummaryTotal>

            <CheckoutButton as={Link} to="/checkout" size="lg">
              <CreditCard size={20} style={{ marginRight: theme.spacing.sm }} />
              Proceed to Checkout
            </CheckoutButton>

            <ContinueShoppingButton to="/menu">
              Continue Shopping
            </ContinueShoppingButton>
          </CardBody>
        </CartSummary>
      </CartContent>
    </CartContainer>
  );
};

export default CartPage;
